Suggested fix: Use a table-driven test:

    func TestFunnelCmds_RequiresSlug(t *testing.T) {
        for _, tc := range []struct {
            name string
            cmd  *cobra.Command
        }{
            {"spark", sparkCmd},
            {"shape", shapeCmd},
            {"specify", specifyCmd},
            {"decompose", decomposeCmd},
        } {
